// Extract YST pair data from DexScreener response
const data = $input.first().json;

// DexScreener returns array of pairs; find SOL pair
const pairs = data.pairs || [];
const ystPair = pairs.find(p => 
  p.quoteToken && p.quoteToken.symbol === 'SOL'
) || pairs[0] || {};

const priceUsd = parseFloat(ystPair.priceUsd || 0);
const priceNative = parseFloat(ystPair.priceNative || 0);
const volume24h = ystPair.volume?.h24 || 0;
const priceChange24h = ystPair.priceChange?.h24 || 0;
const liquidity = ystPair.liquidity?.usd || 0;
const fdv = ystPair.fdv || 0;
const marketCap = ystPair.marketCap || 0;
const buys24h = ystPair.txns?.h24?.buys || 0;
const sells24h = ystPair.txns?.h24?.sells || 0;
const pairAddress = ystPair.pairAddress || 'FhVo3mqL8PW5pH5U2CN4XE33DokiyZnUwuGpH2hmHLuM';

return [{
  json: {
    dexscreener: {
      priceUsd,
      priceNative,
      volume24h,
      priceChange24h,
      liquidity,
      fdv,
      marketCap,
      buys24h,
      sells24h,
      pairAddress,
      pairUrl: ystPair.url || `https://dexscreener.com/solana/${pairAddress}`
    }
  }
}];

// Combine DexScreener + Birdeye data into final payload
const items = $input.all();

// Find dexscreener and birdeye data from merged inputs
const dexItem = items.find(i => i.json.dexscreener) || items[0];
const birdeyeItem = items.find(i => i.json.data) || items[1];

const dex = dexItem?.json?.dexscreener || {};
const bird = birdeyeItem?.json?.data || {};

const timestamp = new Date().toISOString();

const output = {
  token: 'YST',
  name: 'Yakk Studios Token',
  mint: 'jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV',
  chain: 'solana',
  timestamp,
  price: {
    usd: dex.priceUsd || bird.price || 0,
    sol: dex.priceNative || 0
  },
  change24h: dex.priceChange24h || bird.priceChange24hPercent || 0,
  volume: {
    h24: dex.volume24h || bird.v24hUSD || 0
  },
  liquidity: {
    usd: dex.liquidity || 0
  },
  marketCap: dex.marketCap || bird.mc || 0,
  fdv: dex.fdv || bird.fdv || 0,
  transactions: {
    buys24h: dex.buys24h || 0,
    sells24h: dex.sells24h || 0,
    total24h: (dex.buys24h || 0) + (dex.sells24h || 0)
  },
  holders: bird.holder || 0,
  supply: {
    total: bird.supply || 0,
    circulating: bird.circulatingSupply || 0
  },
  links: {
    dexscreener: dex.pairUrl || 'https://dexscreener.com/solana/FhVo3mqL8PW5pH5U2CN4XE33DokiyZnUwuGpH2hmHLuM',
    birdeye: `https://birdeye.so/token/jYwmSavfx69a35JEkpUrxu9JUjvswEvfnhLCDV9vREV?chain=solana`,
    solscan: 'https://solscan.io/token/jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV'
  }
};

return [{ json: output }];
